    fun notesModeDoesNotAlwaysDefaultToCreatedTime() {
        // This test addresses the specific bug: "When you select 'notes', it automatically 
        // sets the display order to 'by created time' oldest to newest"

        val browser = browserWithMultipleNotes

        // Start in cards mode with a non-created-time sort
        browser.changeCardOrder(SortType.SORT_FIELD)
        assertThat("Cards should be sorted by field", browser.mOrder, equalTo(SortType.SORT_FIELD))

        // Switch to notes mode - it should use the default SORT_FIELD, not CREATED_TIME
        browser.switchCardOrNote(NOTES)
        assertThat("Notes mode should not automatically default to CREATED_TIME", 
