        browser.switchCardOrNote(CARDS)
        browser.switchCardOrNote(NOTES)

        // Notes mode should remember DUE_TIME, not reset to CREATED_TIME
        assertThat("Notes mode should remember DUE_TIME sort", browser.mOrder, equalTo(SortType.DUE_TIME))
